{
  "cat_detected": true,
  "pupil_state": "동공 상태",
  "ear_position": "귀 방향",
  "body_posture": "몸의 자세",
  "whisker_direction": "수염 방향",
  "emotion": "감정",
  "confidence_score": 0.0,
  "speech_bubble": "대사"
}

